return items.map(item => {
  try {
    // Buscar automáticamente cualquier campo que parezca contener una fecha
    const dateKeys = Object.keys(item.json).filter(key => {
      const value = String(item.json[key]).trim();
      return /\d{4}[-/]\d{2}[-/]\d{2}/.test(value) || 
             /(?:Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)/i.test(value);
    });

    if (dateKeys.length === 0) {
      throw new Error("No se encontró campo con fecha");
    }

    // Tomar el primer campo de fecha encontrado
    const raw = String(item.json[dateKeys[0]]).trim();

    let año, mes, dia, hora;

    // Patrón 1: "2025-06-2019:44:37"
    const match1 = raw.match(/(\d{4})-(\d{2})-(\d{2})(\d{1,2})/);
    // Patrón 2: "Friday, June 20, 2025 7:44:37 PM"
    const match2 = raw.match(/(?:Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday),\s+(\w+)\s+(\d{1,2}),\s+(\d{4})\s+(\d{1,2})/i);

    if (match1) {
      año = parseInt(match1[1], 10);
      mes = parseInt(match1[2], 10);
      dia = parseInt(match1[3], 10);
      hora = parseInt(match1[4], 10);
    } 
    else if (match2) {
      const monthNames = ["January", "February", "March", "April", "May", "June", 
                         "July", "August", "September", "October", "November", "December"];
      const monthName = match2[1];
      const monthIndex = monthNames.findIndex(m => m.toLowerCase() === monthName.toLowerCase());

      if (monthIndex === -1) throw new Error("Mes inválido");

      año = parseInt(match2[3], 10);
      mes = monthIndex + 1;
      dia = parseInt(match2[2], 10);

      // Convertir hora 12h a 24h
      let rawHora = parseInt(match2[4], 10);
      const period = raw.toLowerCase().includes("pm") ? "pm" : "am";

      if (period === "pm" && rawHora < 12) rawHora += 12;
      if (period === "am" && rawHora === 12) rawHora = 0;

      hora = rawHora;
    } 
    else {
      throw new Error("Formato no reconocido");
    }

    // Validar valores básicos
    if (isNaN(año) || año < 1000) throw new Error("Año inválido");
    if (isNaN(mes) || mes < 1 || mes > 12) throw new Error("Mes inválido");
    if (isNaN(dia) || dia < 1 || dia > 31) throw new Error("Día inválido");
    if (isNaN(hora) || hora < 0 || hora > 23) throw new Error("Hora inválida");

    // Sumar 4 horas y manejar cambio de día/mes/año
    let nuevaHora = hora + 4;
    let nuevoDia = dia;
    let nuevoMes = mes;
    let nuevoAño = año;

    if (nuevaHora >= 24) {
      nuevaHora -= 24;
      nuevoDia++;

      // Manejar cambio de mes
      const diasEnMes = new Date(nuevoAño, nuevoMes, 0).getDate();
      if (nuevoDia > diasEnMes) {
        nuevoDia = 1;
        nuevoMes++;

        // Manejar cambio de año
        if (nuevoMes > 12) {
          nuevoMes = 1;
          nuevoAño++;
        }
      }
    }

    // Formatear componentes a 2 dígitos
    const diaFormateado = String(nuevoDia).padStart(2, '0');
    const mesFormateado = String(nuevoMes).padStart(2, '0');
    const horaFormateada = String(nuevaHora).padStart(2, '0');

    // Crear el formato solicitado: día/mes/año_completo hora (24h) sin minutos ni segundos
    const fechaFormateada = `${diaFormateado}/${mesFormateado}/${nuevoAño} ${horaFormateada}`;

    return {
      json: {
        ...item.json,
        fecha_lora_formateada: fechaFormateada
      }
    };

  } catch (error) {
    return {
      json: {
        ...item.json,
        fecha_lora_formateada: `Error: ${error.message}`
      }
    };
  }
});

// Recupera todos los ítems de entrada
const items = $input.all();

// Mapea cada ítem y formatea el número
const formatted = items.map(item => {
  // 1. Toma la parte antes de "@"
  const raw = item.json.id || '';
  const digits = raw.split('@')[0];

  // 2. Extrae el código de país (primeros 2 dígitos) y el resto
  const countryCode = digits.slice(0, 2);
  const localNumber = digits.slice(2);

  // 3. Construye la cadena "+51 123456789"
  const formattedNumber = `+${countryCode} ${localNumber}`;

  // 4. Guarda el resultado en una nueva propiedad (o sobreescribe `id`)
  item.json.formattedNumber = formattedNumber;
  // — si prefieres sobreescribir el id original:
  // item.json.id = formattedNumber;

  return item;
});

// Devuelve los ítems modificados
return formatted;

// Verifica si hay imagen descargada
if (items[0].binary && items[0].binary.data) {
  const binaryData = items[0].binary.data;

  return [
    {
      json: {
        // Mantiene el texto del usuario para que la IA sepa qué hacer
        query: $('Webhook').item.json.content || "Describe esta imagen",
        // Pasa la imagen en formato que la IA entiende
        imagen_base64: binaryData.data,
        mime_type: binaryData.mimeType
      }
    }
  ];
} else {
  return items; // Si no hay imagen, pasa normal
}
